#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d",&N,&M);
        long long ones=0; char s[100005];
        for(int i=0;i<N;i++){
            scanf("%s",s);
            for(int j=0;j<M;j++) if(s[j]=='1') ones++;
        }
        printf(ones%2?"YES\n":"NO\n");
    }
    return 0;
}

